}

assert_eq!(parser.parse_peek("abcabc"), Ok(("", vec!["abc", "abc"])));
assert_eq!(parser.parse_peek("abc123"), Ok(("123", vec!["abc"])));
assert!(parser.parse_peek("123123").is_err());
assert!(parser.parse_peek("").is_err());
# }
