1236.docs:
Thread global state through your parsers

Use cases
- Recursion checks
- Error recovery
- Debugging

# Example

```
# #[cfg(feature = "ascii")] {
# use std::cell::Cell;
# use winnow::prelude::*;
# use winnow::stream::Stateful;
# use winnow::ascii::alpha1;
# type Error = ();

#[derive(Debug)]
struct State<'s>(&'s mut u32);

impl<'s> State<'s> {
    fn count(&mut self) {
        *self.0 += 1;
    }
}

type Stream<'is> = Stateful<&'is str, State<'is>>;

fn word<'s>(i: &mut Stream<'s>) -> ModalResult<&'s str> {
  i.state.count();
  alpha1.parse_next(i)
}

let data = "Hello";
let mut state = 0;
let input = Stream { input: data, state: State(&mut state) };
let output = word.parse(input).unwrap();
assert_eq!(state, 1);
# }
```

